import React, { useEffect, useState } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';
import MenuBar from './MenuBar';

const TeamIssues = () => {
  const [issues, setIssues] = useState([]);
  const navigate = useNavigate();

  useEffect(() => {
    const fetchIssues = async () => {
      try {
        const token = localStorage.getItem('token');
        const response = await axios.get('http://localhost:3000/api/issues', {
          headers: {
            Authorization: `Bearer ${token}`,
          },
        });

        console.log("Fetched Issues:", response.data); // Debugging log
        setIssues(response.data);
      } catch (error) {
        console.error('Error fetching issues:', error);
        if (error.response && error.response.status === 403) {
          alert('You do not have permission to access this resource.');
          navigate('/dashboard');
        }
      }
    };

    fetchIssues();
  }, [navigate]);

  return (
    <div>
      <MenuBar />
      <h2>Team Reported Issues</h2>
      {issues.length === 0 ? (
        <p>No reported issues available.</p>
      ) : (
        <table className="issues-table">
          <thead>
            <tr>
              <th>Reported By</th>
              <th>Title</th>
              <th>Description</th>
              <th>Date Reported</th>
              <th>Screenshot</th>
            </tr>
          </thead>
          <tbody>
            {issues.map((issue) => (
              <tr key={issue.id}>
                <td>{issue.reported_by || 'Unknown'}</td>
                <td>{issue.title}</td>
                <td>{issue.description}</td>
                <td>{new Date(issue.created_at).toLocaleDateString()}</td>
                <td>
                  {issue.screenshot && issue.screenshot !== 'No screenshot' ? (
                    <a href={`http://localhost:3000/uploads/${issue.screenshot}`} target="_blank" rel="noopener noreferrer">
                      <img 
                        src={`http://localhost:3000/uploads/${issue.screenshot}`} 
                        alt="Screenshot1" 
                        style={{ width: '100px', borderRadius: '5px', cursor: 'pointer' }} 
                      />
                    </a>
                  ) : (
                    <span className="no-screenshot">No screenshot</span>
                  )}
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      )}
    </div>
  );
};

export default TeamIssues;
